const state = $getWorkflowStaticData('global');
const unitName = $('Loop Over Items').item.json.unit_name;
const rows = $input.all();

if (!rows || rows.length === 0) {
  state.summary.push({ unit: unitName, count: 0 });
  return [];
}

const enriched = rows.map(r => ({
  json: { unidade: unitName, ...r.json }
}));

state.rows = [...(state.rows || []), ...enriched];
state.summary.push({ unit: unitName, count: rows.length });

return enriched;

const state = $getWorkflowStaticData('global');
const rows = state.rows || [];
const summary = state.summary || [];

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('pt-BR');

const summaryLines = summary.map(s =>
  s.count > 0
    ? `▪ ${s.unit}: ${s.count} título(s) pago(s) em atraso`
    : `✅ ${s.unit}: sem ocorrências`
).join('\n');

const hasAny = rows.length > 0;

const message = hasAny
  ? `📋 *Pagamentos em Atraso — ${dateStr}*\n\nTítulos pagos após vencimento ontem:\n\n${summaryLines}\n\nDetalhes disponíveis na planilha de controle.`
  : `✅ *Pagamentos em Atraso — ${dateStr}*\n\nNenhum título foi pago em atraso ontem.\n\n${summaryLines}`;

state.rows = [];
state.summary = [];

return [{ json: { rows, message, hasAny } }];

const rows = $json.rows;

if (!rows || rows.length === 0) return [];

const headers = [
  'unidade','titulo','tipo','data_emissao','data_vencimento',
  'data_pagamento','dias_em_atraso','situacao','fornecedor_colaborador',
  'descricao','valor_titulo','centro_custo','plano_conta',
  'classificacao','documento','observacao','usuario','forma_pagamento'
];

// Retorna cada row como item separado para o Sheets
return rows.map(r => ({
  json: Object.fromEntries(headers.map(h => [h, r.json[h] ?? '']))
}));
